import React from "react";
import { ArrowUpRight, ArrowDownLeft } from "lucide-react";
import { formatCurrency } from "../helpers/helpers";

export default function HomeScreen({ balance, savingsBalance, transactions = [], userName, openScreen, darkMode, setDarkMode }) {
  return (
    <div className="px-6 pb-24 bg-gray-50 min-h-screen animate-fade-in">
      {/* Greeting */}
      <h1 className="text-2xl font-bold mb-6">Hello, {userName} 👋</h1>
      <button
      onClick={() => setDarkMode(!darkMode)}
      className="ml-auto text-sm text-gray-400"
    >
      {darkMode ? "☀️" : "🌙"}
    </button>



      {/* Total Balance Card */}
      <div className="bg-gradient-to-br from-emerald-600 to-teal-800 rounded-3xl p-6 text-white shadow-lg shadow-emerald-200 mb-8">
        <div className="flex justify-between items-start mb-2">
          <span className="text-emerald-100 text-sm font-medium">Total Balance</span>
          <span className="text-lg font-bold">Nest.</span>
        </div>
        <div className="text-4xl font-bold mb-4 tracking-tight">${formatCurrency(balance)}</div>

        {/* Savings Balance */}
        <p className="text-emerald-200 font-medium mb-4">
          Savings: ${formatCurrency(savingsBalance)}
        </p>

        {/* Buttons */}
        <div className="flex gap-3">
          <button
            onClick={() => openScreen("Deposit")}
            className="flex-1 bg-white/20 backdrop-blur-sm py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium hover:bg-white/30 transition-colors"
          >
            <ArrowUpRight className="w-4 h-4" /> Deposit
          </button>

          <button
            onClick={() => openScreen("Withdraw")}
            className="flex-1 bg-white/20 backdrop-blur-sm py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium hover:bg-white/30 transition-colors"
          >
            <ArrowDownLeft className="w-4 h-4" /> Withdraw
          </button>
        </div>

        {/* Savings actions */}
        <div className="flex gap-3 mt-3">
          <button
            onClick={() => openScreen("SavingsDeposit")}
            className="flex-1 bg-emerald-500/20 backdrop-blur-sm py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium hover:bg-emerald-500/30 transition-colors"
          >
            Save
          </button>

          <button
            onClick={() => openScreen("SavingsWithdraw")}
            className="flex-1 bg-emerald-500/20 backdrop-blur-sm py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium hover:bg-red-500/30 transition-colors"
          >
            Withdraw Savings
          </button>
        </div>
      </div>

      {/* Recent Transactions */}
      <div>
        <div className="flex justify-between items-center mb-4">
          <h2 className="font-bold text-gray-800 text-lg">Recent Transactions</h2>
          <button
            onClick={() => openScreen("Transactions")}
            className="text-gray-400"
          >
            ▶
          </button>
        </div>

        <div className="space-y-4">
          {transactions.slice(0, 5).map((t) => (
            <div
              key={t.id}
              className="flex items-center justify-between bg-white p-3 rounded-xl border border-gray-50 cursor-pointer hover:bg-gray-50"
              onClick={() => openScreen("TransactionReceipt")}
            >
              <div className="flex items-center gap-3">
                <div
                  className={`w-10 h-10 rounded-full flex items-center justify-center ${
                    t.type.includes("deposit") ? "bg-emerald-100 text-emerald-600" : "bg-red-100 text-red-600"
                  }`}
                >
                  {t.type.includes("deposit") ? <ArrowDownLeft className="w-5 h-5" /> : <ArrowUpRight className="w-5 h-5" />}
                </div>
                <div>
                  <p className="font-semibold text-gray-800">{t.title}</p>
                  <p className="text-xs text-gray-400">{t.date}</p>
                </div>
              </div>
              <span
                className={`font-bold text-sm ${
                  t.type.includes("deposit") ? "text-emerald-600" : "text-gray-800"
                }`}
              >
                {t.type.includes("deposit") ? "+" : "-"}${formatCurrency(t.amount)}
              </span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
